(()=>{const KEY='mode';const root=document.documentElement;const mq=window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)');const apply=m=>{if(m==='dark'||m==='light'){root.setAttribute('data-mode',m);}else{root.removeAttribute('data-mode');}};const stored=(()=>{try{return localStorage.getItem(KEY);}catch{return null;}})();apply(stored);const btn=document.getElementById('mode-toggle');const next=()=>{const current=root.getAttribute('data-mode')||((mq&&mq.matches)?'dark':'light');return current==='dark'?'light':'dark';};if(btn){btn.addEventListener('click',()=>{const m=next();apply(m);try{localStorage.setItem(KEY,m);}catch{}});}if(mq&&mq.addEventListener){mq.addEventListener('change',()=>{const v=(()=>{try{return localStorage.getItem(KEY);}catch{return null;}})();if(!v)apply(null);});}})();
